import os

def fix_projects():
    # Use project_list.txt which is generated by list_projects.ps1
    with open('project_list.txt', 'r', encoding='utf-8-sig') as f:
        projects = [line.strip() for line in f if line.strip()]

    for proj_rel_path in projects:
        # project_list.txt contains paths relative to v1/src, so we need to prepend v1/src
        # Wait, list_projects.ps1 outputs paths like "TarsEngine.FSharp.Core\TarsEngine.FSharp.Core.fsproj"
        # So we prepend v1/src/
        proj_path = os.path.join('v1/src', proj_rel_path)
        
        if not os.path.exists(proj_path):
            print(f"Skipping missing project: {proj_path}")
            continue

        print(f"Processing {proj_path}...")
        try:
            with open(proj_path, 'r', encoding='utf-8') as f:
                content = f.read()

            # 1. Upgrade to net10.0
            if '<TargetFramework>net9.0</TargetFramework>' in content:
                content = content.replace('<TargetFramework>net9.0</TargetFramework>', '<TargetFramework>net10.0</TargetFramework>')
                print("  Upgraded to net10.0")
            
            # 2. Remove C# references
            lines = content.splitlines()
            new_lines = []
            for line in lines:
                if 'ProjectReference' in line and '.csproj' in line:
                    print(f"  Removing reference: {line.strip()}")
                    continue # Skip this line
                new_lines.append(line)
            
            new_content = '\n'.join(new_lines)
            
            if new_content != content:
                with open(proj_path, 'w', encoding='utf-8') as f:
                    f.write(new_content)
                print("  Saved changes.")
                
        except Exception as e:
            print(f"Error processing {proj_path}: {e}")

if __name__ == '__main__':
    fix_projects()
